<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  :root {
    --ink: #0a0c1a;
    --deep: #080b18;
    --gold: #d4a017;
    --gold-light: #f0c84a;
    --gold-pale: #fde99a;
    --blue: #5bb8d4;
    --blue-glow: #7dd8f0;
    --blue-pale: #c2edf8;
    --white: #f8f4ee;
    --mist: rgba(248,244,238,0.07);
  }

  body {
    background: var(--deep);
    font-family: 'Noto Serif SC', serif;
    color: var(--white);
    width: 800px;
    margin: 0 auto;
    overflow-x: hidden;
  }

  /* ── STAR CANVAS ── */
  .starfield {
    position: fixed;
    inset: 0;
    pointer-events: none;
    z-index: 0;
  }

  /* ── HERO ── */
  .hero {
    position: relative;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 80px 60px 60px;
    overflow: hidden;
    z-index: 1;
  }

  .hero::before {
    content: '';
    position: absolute;
    inset: 0;
    background:
      radial-gradient(ellipse 60% 50% at 50% 30%, rgba(91,184,212,0.12) 0%, transparent 70%),
      radial-gradient(ellipse 40% 60% at 20% 80%, rgba(212,160,23,0.08) 0%, transparent 60%),
      radial-gradient(ellipse 50% 40% at 80% 70%, rgba(91,184,212,0.06) 0%, transparent 60%);
  }

  /* Moon */
  .moon {
    position: absolute;
    top: 40px;
    right: 80px;
    width: 90px;
    height: 90px;
    border-radius: 50%;
    background: radial-gradient(circle at 35% 35%, var(--gold-pale), var(--gold) 60%, #a07010);
    box-shadow: 0 0 30px rgba(212,160,23,0.4), 0 0 80px rgba(212,160,23,0.15);
    animation: moonPulse 4s ease-in-out infinite;
  }
  .moon::after {
    content: '';
    position: absolute;
    top: 12px; right: 8px;
    width: 65px; height: 65px;
    border-radius: 50%;
    background: radial-gradient(circle at 40% 40%, rgba(255,255,255,0.15), transparent 70%);
  }
  @keyframes moonPulse {
    0%,100% { box-shadow: 0 0 30px rgba(212,160,23,0.4), 0 0 80px rgba(212,160,23,0.15); }
    50% { box-shadow: 0 0 50px rgba(212,160,23,0.6), 0 0 120px rgba(212,160,23,0.25); }
  }

  /* Tag line above title */
  .eyebrow {
    font-family: 'Cinzel Decorative', serif;
    font-size: 11px;
    letter-spacing: 0.4em;
    color: var(--blue);
    text-transform: uppercase;
    margin-bottom: 20px;
    opacity: 0.85;
    animation: fadeUp 1s ease 0.2s both;
  }

  /* Main title */
  .title-wrap {
    text-align: center;
    margin-bottom: 18px;
    animation: fadeUp 1s ease 0.4s both;
  }
  .title-en {
    font-family: 'Cinzel Decorative', serif;
    font-size: 68px;
    font-weight: 700;
    letter-spacing: 0.05em;
    background: linear-gradient(135deg, var(--gold-pale) 0%, var(--gold) 40%, var(--gold-light) 70%, var(--gold-pale) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    filter: drop-shadow(0 0 20px rgba(212,160,23,0.5));
    line-height: 1.1;
  }
  .title-zh {
    font-family: 'Noto Serif SC', serif;
    font-size: 18px;
    font-weight: 300;
    letter-spacing: 0.6em;
    color: var(--blue-pale);
    margin-top: 8px;
    opacity: 0.8;
  }

  /* Divider */
  .divider {
    display: flex;
    align-items: center;
    gap: 16px;
    margin: 28px auto;
    width: 320px;
    animation: fadeUp 1s ease 0.6s both;
  }
  .divider-line {
    flex: 1;
    height: 1px;
    background: linear-gradient(90deg, transparent, var(--gold), transparent);
  }
  .divider-gem {
    width: 8px; height: 8px;
    background: var(--gold-light);
    transform: rotate(45deg);
    box-shadow: 0 0 8px var(--gold);
  }

  /* Character illustration SVG */
  .char-wrap {
    position: relative;
    width: 250px;
    height: 250px;
    margin: 10px auto 30px;
    display: flex;
    align-items: center;
    justify-content: center;
    animation: fadeUp 1s ease 0.7s both;
  }

  .char-glow {
    position: absolute;
    bottom: 20px;
    left: 50%;
    transform: translateX(-50%);
    width: 180px;
    height: 30px;
    background: radial-gradient(ellipse, rgba(91,184,212,0.4) 0%, transparent 70%);
    border-radius: 50%;
    filter: blur(8px);
    animation: glowPulse 3s ease-in-out infinite;
  }
  @keyframes glowPulse {
    0%,100% { opacity: 0.6; transform: translateX(-50%) scaleX(1); }
    50% { opacity: 1; transform: translateX(-50%) scaleX(1.15); }
  }

  /* The cat SVG */
  .luna-svg {
    width: 100%;
    height: 100%;
    filter: drop-shadow(0 0 18px rgba(91,184,212,0.35)) drop-shadow(0 0 40px rgba(212,160,23,0.2));
    animation: floatCat 5s ease-in-out infinite;
  }
  @keyframes floatCat {
    0%,100% { transform: translateY(0); }
    50% { transform: translateY(-12px); }
  }

  /* Star shine effect */
  .star-shine-container {
    position: relative;
    display: inline-block;
    transition: transform 0.3s ease;
  }

  .star-shine-container:hover {
    transform: scale(1.05);
  }

  .star-shine {
    position: absolute;
    width: 4px;
    height: 4px;
    background: rgba(255, 255, 255, 0.8);
    border-radius: 50%;
    box-shadow: 0 0 8px 2px rgba(91, 184, 212, 0.6), 0 0 12px 4px rgba(212, 160, 23, 0.4);
    opacity: 0;
    pointer-events: none;
    animation: starBurst 3s ease-in-out infinite;
  }

  .star-shine:nth-child(2) { top: 10%; left: 15%; animation-delay: 0s; }
  .star-shine:nth-child(3) { top: 25%; right: 10%; animation-delay: 0.5s; }
  .star-shine:nth-child(4) { bottom: 20%; left: 20%; animation-delay: 1s; }
  .star-shine:nth-child(5) { bottom: 10%; right: 15%; animation-delay: 1.5s; }
  .star-shine:nth-child(6) { top: 50%; left: 5%; animation-delay: 2s; }

  @keyframes starBurst {
    0% {
      transform: scale(0);
      opacity: 0;
    }
    20% {
      transform: scale(1);
      opacity: 1;
    }
    100% {
      transform: scale(0);
      opacity: 0;
    }
  }

  .star-shine-container:hover .star-shine {
    animation-duration: 1s;
  }

  /* Star shine effect */
  .star-shine-container {
    position: relative;
