  /* Orbiting sparkles */
  .sparkle {
    position: absolute;
    border-radius: 50%;
    animation: orbit linear infinite;
    pointer-events: none;
  }
  @keyframes orbit {
    from { transform: rotate(var(--start)) translateX(var(--r)) rotate(calc(var(--start) * -1)) scale(1); opacity: 0.9; }
    50% { opacity: 0.4; transform: rotate(calc(var(--start) + 180deg)) translateX(var(--r)) rotate(calc((var(--start) + 180deg) * -1)) scale(0.7); }
    to { transform: rotate(calc(var(--start) + 360deg)) translateX(var(--r)) rotate(calc((var(--start) + 360deg) * -1)) scale(1); opacity: 0.9; }
  }

  /* Hero sub copy */
  .hero-copy {
    text-align: center;
    max-width: 460px;
    animation: fadeUp 1s ease 0.9s both;
  }
  .hero-tagline {
    font-family: 'Playfair Display', serif;
    font-style: italic;
    font-size: 20px;
    color: var(--blue-pale);
    letter-spacing: 0.05em;
    line-height: 1.7;
    margin-bottom: 14px;
  }
  .hero-sub {
    font-size: 13px;
    font-weight: 300;
    letter-spacing: 0.15em;
    color: rgba(248,244,238,0.45);
    line-height: 2;
  }

  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(24px); }
    to { opacity: 1; transform: translateY(0); }
  }

  /* ── SECTION: LORE ── */
  .lore {
    position: relative;
    z-index: 1;
    padding: 70px 60px;
    background: linear-gradient(180deg, transparent 0%, rgba(91,184,212,0.04) 50%, transparent 100%);
  }
  .lore-inner {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 40px;
    align-items: center;
  }
  .lore-text h2 {
    font-family: 'Cinzel Decorative', serif;
    font-size: 13px;
    letter-spacing: 0.35em;
    color: var(--gold);
    margin-bottom: 20px;
    opacity: 0.9;
  }
  .lore-text p {
    font-size: 14px;
    font-weight: 300;
    line-height: 2.2;
    color: rgba(248,244,238,0.75);
    letter-spacing: 0.06em;
  }
  .lore-stat-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 16px;
  }
  .stat-card {
    border: 1px solid rgba(212,160,23,0.2);
    border-radius: 12px;
    padding: 20px 16px;
    background: rgba(212,160,23,0.04);
    text-align: center;
    position: relative;
    overflow: hidden;
    transition: border-color 0.3s, background 0.3s;
  }
  .stat-card::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 2px;
    background: linear-gradient(90deg, transparent, var(--gold-light), transparent);
    opacity: 0.6;
  }
  .stat-card:hover {
    border-color: rgba(212,160,23,0.5);
    background: rgba(212,160,23,0.08);
  }
  .stat-icon { font-size: 22px; margin-bottom: 8px; }
  .stat-label {
    font-size: 11px;
    letter-spacing: 0.25em;
    color: var(--gold);
    opacity: 0.7;
    margin-bottom: 4px;
  }
  .stat-value {
    font-family: 'Cinzel Decorative', serif;
    font-size: 13px;
    color: var(--white);
  }

  /* ── SECTION: PALETTE ── */
  .palette-section {
    position: relative;
    z-index: 1;
    padding: 60px 60px;
  }
  .section-title {
    font-family: 'Cinzel Decorative', serif;
    font-size: 11px;
    letter-spacing: 0.4em;
