  }
  .palette-plus {
    font-family: 'Cinzel Decorative', serif;
    font-size: 20px;
    color: rgba(248,244,238,0.2);
    margin-bottom: 22px;
  }

  /* ── SECTION: TRAITS ── */
  .traits {
