  }
  .traits-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
  }
  .trait-card {
    border: 1px solid rgba(91,184,212,0.15);
    border-radius: 16px;
    padding: 28px 20px;
    text-align: center;
    background: rgba(91,184,212,0.03);
