    <div class="lore-stat-grid">
      <div class="stat-card">
        <div class="stat-icon">🌙</div>
        <div class="stat-label">ORIGIN</div>
        <div class="stat-value">月 轨 界</div>
      </div>
      <div class="stat-card">
        <div class="stat-icon">✦</div>
        <div class="stat-label">ELEMENT</div>
        <div class="stat-value">星 与 金</div>
      </div>
