<script>
// ── Stars ──
const canvas = document.getElementById('stars');
const ctx = canvas.getContext('2d');
let W, H;

function resize() {
  W = canvas.width = window.innerWidth;
  H = canvas.height = document.body.scrollHeight;
}
resize();
window.addEventListener('resize', resize);

const stars = Array.from({length: 220}, () => ({
  x: Math.random(), y: Math.random(),
  r: Math.random() * 1.4 + 0.2,
  alpha: Math.random() * 0.7 + 0.1,
  speed: Math.random() * 0.012 + 0.004,
  phase: Math.random() * Math.PI * 2,
  color: Math.random() > 0.7 ? '#d4a017' : Math.random() > 0.5 ? '#5bb8d4' : '#f8f4ee'
}));

function drawStars(t) {
  ctx.clearRect(0, 0, W, H);
  stars.forEach(s => {
    const a = s.alpha * (0.5 + 0.5 * Math.sin(t * s.speed + s.phase));
    ctx.beginPath();
    ctx.arc(s.x * W, s.y * H, s.r, 0, Math.PI * 2);
    ctx.fillStyle = s.color;
    ctx.globalAlpha = a;
    ctx.fill();
  });
  ctx.globalAlpha = 1;
  requestAnimationFrame(drawStars);
}
requestAnimationFrame(drawStars);

// ── Floating particles ──
const body = document.body;
function spawnParticle() {
  const p = document.createElement('div');
  p.className = 'particle';
  const isGold = Math.random() > 0.5;
  const size = Math.random() * 3 + 1;
  p.style.cssText = `
    width:${size}px;height:${size}px;
    left:${Math.random()*100}%;
    background:${isGold ? '#f0c84a' : '#5bb8d4'};
    opacity:${Math.random()*0.5+0.2};
    animation-duration:${Math.random()*12+8}s;
    animation-delay:${Math.random()*8}s;
    box-shadow:0 0 ${size*3}px ${isGold ? '#f0c84a' : '#5bb8d4'};
  `;
  body.appendChild(p);
  setTimeout(() => p.remove(), 20000);
}
setInterval(spawnParticle, 1200);
for(let i=0;i<8;i++) spawnParticle();
</script>
